<?php
namespace App\Filament\Resources; use App\Filament\Resources\NotificationResource\Pages; use App\Modules\Notification\Models\Notification; use Filament\Forms; use Filament\Forms\Form; use Filament\Resources\Resource; use Filament\Tables; use Filament\Tables\Table;
class NotificationResource extends Resource { protected static ?string $model=Notification::class; protected static ?string $navigationIcon='heroicon-o-bell'; protected static ?string $navigationGroup='Hệ thống'; protected static ?string $modelLabel='Thông báo'; protected static ?string $pluralModelLabel='Thông báo'; public static function form(Form $form): Form { return $form->schema([Forms\Components\TextInput::make('type')->label('Loại')->required()->columnSpanFull(), Forms\Components\TextInput::make('notifiable_type')->label('Loại người nhận')->required(), Forms\Components\TextInput::make('notifiable_id')->label('ID người nhận')->required(), Forms\Components\KeyValue::make('data')->label('Nội dung payload')->columnSpanFull(), Forms\Components\DateTimePicker::make('read_at')->label('Đã đọc lúc')])->columns(2); } public static function table(Table $table): Table { return $table->columns([Tables\Columns\TextColumn::make('data.title')->label('Tiêu đề')->limit(40), Tables\Columns\TextColumn::make('data.body')->label('Nội dung')->limit(60), Tables\Columns\TextColumn::make('notifiable_id')->label('Người nhận')->limit(12), Tables\Columns\IconColumn::make('read_at')->label('Đã đọc')->boolean(), Tables\Columns\TextColumn::make('created_at')->label('Ngày gửi')->dateTime('d/m/Y H:i')])->actions([Tables\Actions\EditAction::make(),Tables\Actions\DeleteAction::make()]); } public static function getPages(): array { return ['index'=>Pages\ListNotifications::route('/'),'create'=>Pages\CreateNotification::route('/create'),'edit'=>Pages\EditNotification::route('/{record}/edit')]; } }
